"use client";

import { useState, useEffect } from "react";

interface HealthResponse {
  status: string;
  timestamp: string;
  service: string;
  version: string;
}

export default function HealthStatus() {
  const [health, setHealth] = useState<HealthResponse | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchHealth = async () => {
    try {
      setLoading(true);
      setError(null);

      const response = await fetch("http://localhost:8000/api/v1/health");

      if (!response.ok) {
        throw new Error(`HTTP ${response.status}: ${response.statusText}`);
      }

      const data: HealthResponse = await response.json();
      setHealth(data);
    } catch (err) {
      setError(
        err instanceof Error ? err.message : "Failed to fetch health status"
      );
      setHealth(null);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchHealth();
    // Refresh health status every 30 seconds
    const interval = setInterval(fetchHealth, 30000);
    return () => clearInterval(interval);
  }, []);

  const getStatusColor = () => {
    if (loading) return "text-gray-500";
    if (error) return "text-red-500";
    if (health?.status === "healthy") return "text-green-500";
    return "text-yellow-500";
  };

  const getStatusText = () => {
    if (loading) return "Checking...";
    if (error) return "Offline";
    if (health?.status === "healthy") return "Online";
    return health?.status || "Unknown";
  };

  return (
    <div className="bg-card border border-border rounded-lg p-6 shadow-sm">
      <div className="flex items-center justify-between mb-4">
        <h3 className="text-lg font-semibold">API Status</h3>
        <div className="flex items-center gap-2">
          <div
            className={`w-3 h-3 rounded-full ${
              loading
                ? "bg-gray-500"
                : error
                ? "bg-red-500"
                : health?.status === "healthy"
                ? "bg-green-500"
                : "bg-yellow-500"
            }`}
          />
          <span className={`font-medium ${getStatusColor()}`}>
            {getStatusText()}
          </span>
        </div>
      </div>

      {error && (
        <div className="text-red-600 text-sm mb-4">
          <p>Error: {error}</p>
          <p className="text-muted-foreground mt-1">
            Make sure the backend is running on http://localhost:8000
          </p>
        </div>
      )}

      {health && (
        <div className="space-y-2 text-sm">
          <div className="flex justify-between">
            <span className="text-muted-foreground">Service:</span>
            <span>{health.service}</span>
          </div>
          <div className="flex justify-between">
            <span className="text-muted-foreground">Version:</span>
            <span>{health.version}</span>
          </div>
          <div className="flex justify-between">
            <span className="text-muted-foreground">Last Check:</span>
            <span>{new Date(health.timestamp).toLocaleTimeString()}</span>
          </div>
        </div>
      )}

      <button
        onClick={fetchHealth}
        disabled={loading}
        className="mt-4 w-full bg-primary text-primary-foreground hover:bg-primary/90 disabled:opacity-50 disabled:cursor-not-allowed px-4 py-2 rounded-md text-sm font-medium transition-colors"
      >
        {loading ? "Checking..." : "Refresh Status"}
      </button>
    </div>
  );
}
